class Rectangle {
  setWidth(w: number): void { }
  setHeight(h: number): void { }
  area(): number { return 0; }
}
class Square extends Rectangle {
  setWidth(w: number): void { super.setWidth(w); super.setHeight(w); }
  setHeight(h: number): void { super.setWidth(h); super.setHeight(h); }
}
function stretchWidth(r: Rectangle): void {
  r.setWidth(10);
  r.setHeight(2);
}

interface BaseRepo {
  save(user: User): void;
}
class SqlRepo implements BaseRepo {
  save(user: User): void { /* persists valid user */ }
}
class ReadOnlyRepo implements BaseRepo {
  save(user: User): void {
    throw new Error('Writes disabled in read-only mode');
  }
}
function register(repo: BaseRepo, user: User): void { repo.save(user); }

// Version A
interface Notifier { send(msg: string): void; }
class EmailNotifier implements Notifier {
  send(msg: string): void { this.smtp.send(msg); }
}
class DisabledNotifier implements Notifier {
  send(msg: string): void { throw new Error('Notifications disabled'); }
}
// Version B
interface Notifier { send(msg: string): boolean; }
class DisabledNotifier implements Notifier {
  send(msg: string): boolean { return false; }
}
